('spanish:8-2-social-media-and-online-safety:match:bb6de1f6', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “el impacto”?", "options": ["the issue / matter", "personal data", "to chat", "the impact"]}'::jsonb, '{"answer": 3, "explain": "“el impacto” means: the impact"}'::jsonb),
('spanish:8-2-social-media-and-online-safety:match:c8721816', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “de acuerdo”?", "options": ["safe", "to chat", "to comment", "agreed / OK"]}'::jsonb, '{"answer": 3, "explain": "“de acuerdo” means: agreed / OK"}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:cec4172a', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"en mi barrio hay muchas tiendas\" data-listen></span><br>Listen. What is being said?", "options": ["There are many shops in my area", "There is a big shopping centre near my house", "There aren’t any shops in my town", "There used to be many shops in my area"]}'::jsonb, '{"answer": 0, "explain": "‘en mi barrio hay muchas tiendas’ = there are many shops in my area. The traps add detail, reverse the meaning with a negative, or change the tense."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:3cd1ef7c', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"se puede nadar en el polideportivo\" data-listen></span><br>Listen. What can you do?", "options": ["You can swim at the sports centre", "You cannot swim at the sports centre", "You can swim in the sea near the town", "You used to be able to swim at the sports centre"]}'::jsonb, '{"answer": 0, "explain": "‘se puede nadar en el polideportivo’ = you can swim at the sports centre. Trap B negates it; C changes the place; D changes the tense."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:2c50775a', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "How do you say ‘there isn’t a swimming pool in my town’?", "options": ["No hay piscina en mi pueblo", "Hay piscina en mi pueblo", "No hay piscinas en mi ciudad grande", "No había piscina en mi pueblo"]}'::jsonb, '{"answer": 0, "explain": "no hay + noun = there isn’t. B drops the negative (opposite meaning); C adds extra detail and changes place; D shifts to the imperfect (there wasn’t, used to be)."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:ab618c33', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which sentence uses ‘estar’ correctly for location?", "options": ["El parque está al lado del ayuntamiento", "El parque es al lado del ayuntamiento", "El parque hay al lado del ayuntamiento", "El parque tiene al lado del ayuntamiento"]}'::jsonb, '{"answer": 0, "explain": "Location always uses estar. B wrongly uses ser; C wrongly uses hay; D wrongly uses tener."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:c2855b60', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "What does ‘el cuarto de baño’ mean?", "options": ["the bathroom", "the bedroom, upstairs near the garden", "the kitchen, next to the living room", "the living room, which is usually downstairs"]}'::jsonb, '{"answer": 0, "explain": "el cuarto de baño = the bathroom. Don’t confuse it with el dormitorio (bedroom), la cocina (kitchen) or el salón (living room)."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:a5c59140', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Mi pueblo es más tranquilo ___ la ciudad.’", "options": ["que", "como", "de", "muy"]}'::jsonb, '{"answer": 0, "explain": "Comparatives need más/menos + adjective + QUE. ‘como’ means ‘as/like’, ‘de’ means ‘of/from’, and ‘muy’ (very) does not fit here."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:320eb4c9', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "‘Antes vivía en un piso pequeño’ is in which tense?", "options": ["the imperfect tense (used to)", "the ordinary present tense (right now)", "the near future (going to)", "a direct command"]}'::jsonb, '{"answer": 0, "explain": "vivía is imperfect, matching ‘antes’ (before/in the past). It is not present, future or a command."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:8038abea', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ‘noisy’?", "options": ["ruidoso", "tranquilo", "limpio", "animado"]}'::jsonb, '{"answer": 0, "explain": "ruidoso = noisy. tranquilo means quiet (the opposite), limpio means clean and animado means lively."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:549646cf', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "What does ‘en las afueras’ mean?", "options": ["on the outskirts", "in the town centre, near the shops", "next to the station, by the park", "between two shops, near the market"]}'::jsonb, '{"answer": 0, "explain": "en las afueras = on the outskirts. El centro is the town centre — the opposite idea."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:daed43db', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "‘No hay’ + a noun means…", "options": ["there isn’t / there aren’t — a negative", "there is definitely one nearby", "you are not allowed to go there at all today", "there won’t be one there next year"]}'::jsonb, '{"answer": 0, "explain": "no hay = there isn’t/aren’t, simply the negative of hay. It does not mean ‘forbidden’, ‘certain’ or change the tense."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:fc877b00', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ''distance''?", "options": ["la distancia", "la velocidad", "la altura", "el ruido"]}'::jsonb, '{"answer": 0, "explain": "la distancia = distance. la velocidad = speed, la altura = height, el ruido = noise — related measurements, but each is different."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:3d771dd1', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ''to steal''?", "options": ["robar", "cobrar", "devolver", "cometer"]}'::jsonb, '{"answer": 0, "explain": "robar = to steal. cobrar = to charge/get paid, devolver = to give back, cometer = to commit (e.g. cometer un delito)."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:a639ba66', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ''a crime''?", "options": ["un delito", "un accidente", "una señal", "una venta"]}'::jsonb, '{"answer": 0, "explain": "un delito = a crime. un accidente = an accident, una señal = a sign/signal, una venta = a sale — all things a local news story might mention."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:647caac4', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ''empty''?", "options": ["vacío", "hermoso", "grande", "pequeño"]}'::jsonb, '{"answer": 0, "explain": "vacío = empty. hermoso = beautiful, grande = big, pequeño = small — all common adjectives for describing a house or place."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:3fbe332e', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ''height''?", "options": ["la altura", "el tamaño", "la distancia", "la velocidad"]}'::jsonb, '{"answer": 0, "explain": "la altura = height. el tamaño = size, la distancia = distance, la velocidad = speed — all measurements, but each means something different."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:mcq:fddc8d15', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'mcq', 'mcq', 1, '{"question": "Which word means ''a sign'' or ''a signal''?", "options": ["una señal", "un delito", "un accidente", "una venta"]}'::jsonb, '{"answer": 0, "explain": "una señal = a sign/signal (e.g. a road sign). un delito = a crime, un accidente = an accident, una venta = a sale."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:e9cd7dba', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘hay’ changes to ‘han’ when you talk about more than one thing."}'::jsonb, '{"answer": false, "explain": "hay is invariable — it never changes, whether singular or plural."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:7bd67226', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘se puede’ is followed by an infinitive."}'::jsonb, '{"answer": true, "explain": "se puede nadar / comprar / visitar — always an infinitive."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:c6aacbea', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "Location (where something is) uses ‘estar’, not ‘ser’."}'::jsonb, '{"answer": true, "explain": "El parque está cerca de mi casa — location always takes estar."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:2a16f3a2', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘el ayuntamiento’ means ‘the shopping centre’."}'::jsonb, '{"answer": false, "explain": "el ayuntamiento = town hall; el centro comercial = shopping centre."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:4967cfe1', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "Comparatives use ‘más / menos + adjective + que’."}'::jsonb, '{"answer": true, "explain": "Mi pueblo es más tranquilo QUE la ciudad."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:2da1c296', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘antes vivía’ is in the present tense."}'::jsonb, '{"answer": false, "explain": "vivía is the imperfect tense (used to live), not the present."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:8c7584aa', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘tranquilo’ and ‘ruidoso’ are opposites."}'::jsonb, '{"answer": true, "explain": "tranquilo = quiet, ruidoso = noisy."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:6975c944', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘en las afueras’ means ‘in the town centre’."}'::jsonb, '{"answer": false, "explain": "en las afueras = on the outskirts; el centro = the town centre."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:0d077e62', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘el vecino’ means ‘the neighbour’."}'::jsonb, '{"answer": true, "explain": "el vecino / la vecina = neighbour."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:caab4cc1', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘abandonado’ means ‘brand new’."}'::jsonb, '{"answer": false, "explain": "abandonado means abandoned/deserted, not brand new (nuevo)."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:1cca150d', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘cruzar’ means ‘to cross’."}'::jsonb, '{"answer": true, "explain": "cruzar la calle = to cross the street."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tf:bc6d2e16', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tf', 'tf', 1, '{"question": "‘la piedra’ means ‘brick’."}'::jsonb, '{"answer": false, "explain": "la piedra means stone; a brick is un ladrillo."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:d7a8c1ea', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe my home?", "reading": "<p>Use <span data-say=\"vivir\">vivir</span> (to live) with <strong>en</strong> to say where you live. The two key words for ‘home’ are:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la casa\">la casa</span></td><td>house</td><td><span data-say=\"el piso\">el piso</span></td><td>flat / apartment</td></tr>\n              <tr><td><span data-say=\"la habitación\">la habitación</span></td><td>room</td><td><span data-say=\"cómodo\">cómodo / cómoda</span></td><td>comfortable</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Vivo en una casa cómoda en las afueras de la ciudad.\">Vivo en una casa cómoda en las afueras de la ciudad.</span> — <em>I live in a comfortable house on the outskirts of the city.</em></p>", "question": "What does ‘Vivo en un piso’ mean?", "options": ["I live in a flat", "I live in a big house with a garden", "I used to live in a flat", "I would like to live in a flat"]}'::jsonb, '{"answer": 0, "explain": "vivo = I live (present tense); el piso = flat/apartment. The distractors change the tense or add details that are not there."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:3a169204', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "What rooms are there in my house?", "reading": "<p>Use <span data-say=\"hay\">hay</span> (there is / there are) to list the rooms — <strong>hay never changes</strong>, whether you mean one thing or several.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el dormitorio\">el dormitorio</span></td><td>bedroom</td><td><span data-say=\"el salón\">el salón</span></td><td>living room</td></tr>\n              <tr><td><span data-say=\"la cocina\">la cocina</span></td><td>kitchen</td><td><span data-say=\"el cuarto de baño\">el cuarto de baño</span></td><td>bathroom</td></tr>\n              <tr><td><span data-say=\"el jardín\">el jardín</span></td><td>garden</td><td><span data-say=\"arriba\">arriba</span> / <span data-say=\"abajo\">abajo</span></td><td>upstairs / downstairs</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En mi casa hay cuatro dormitorios arriba y la cocina está abajo.\">En mi casa hay cuatro dormitorios arriba y la cocina está abajo.</span> — <em>In my house there are four bedrooms upstairs and the kitchen is downstairs.</em></p>", "question": "Where is ‘la cocina’ in the model sentence?", "options": ["downstairs", "upstairs, next to the bedrooms", "in the garden behind the house", "in the bathroom on the first floor"]}'::jsonb, '{"answer": 0, "explain": "la cocina está abajo = the kitchen is downstairs. Don’t confuse arriba (upstairs) with abajo (downstairs)."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:12af6af4', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe my town or area?", "reading": "<p>Key places in a <span data-say=\"el barrio\">barrio</span> (neighbourhood):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la ciudad\">la ciudad</span></td><td>city</td><td><span data-say=\"el pueblo\">el pueblo</span></td><td>town / village</td></tr>\n              <tr><td><span data-say=\"el centro\">el centro</span></td><td>town centre</td><td><span data-say=\"las tiendas\">las tiendas</span></td><td>shops</td></tr>\n              <tr><td><span data-say=\"el centro comercial\">el centro comercial</span></td><td>shopping centre</td><td><span data-say=\"el polideportivo\">el polideportivo</span></td><td>sports centre</td></tr>\n              <tr><td><span data-say=\"la estación\">la estación</span></td><td>station</td><td><span data-say=\"el ayuntamiento\">el ayuntamiento</span></td><td>town hall</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En mi pueblo hay un polideportivo y un centro comercial cerca del ayuntamiento.\">En mi pueblo hay un polideportivo y un centro comercial cerca del ayuntamiento.</span> — <em>In my town there is a sports centre and a shopping centre near the town hall.</em></p>", "question": "What is ‘el ayuntamiento’?", "options": ["the town hall", "the shopping centre near the station", "the train station in the centre", "the sports centre building"]}'::jsonb, '{"answer": 0, "explain": "el ayuntamiento = town hall. Don’t confuse it with el centro comercial (shopping centre) or la estación (station)."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:007a98d4', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "How do I say what there is (or isn’t) and what you can do?", "reading": "<p><span data-say=\"hay\">Hay</span> (there is/are) and <span data-say=\"no hay\">no hay</span> (there isn’t/aren’t) never change form. To say what is possible, use <span data-say=\"se puede\">se puede</span> + infinitive (you can / one can).</p>\n            <ul>\n              <li><span data-say=\"En mi barrio hay muchas tiendas.\">En mi barrio hay muchas tiendas.</span> — In my area there are many shops.</li>\n              <li><span data-say=\"No hay piscina en mi pueblo.\">No hay piscina en mi pueblo.</span> — There isn’t a swimming pool in my town.</li>\n              <li><span data-say=\"Se puede nadar en el polideportivo.\">Se puede nadar en el polideportivo.</span> — You can swim at the sports centre.</li>\n            </ul>", "question": "What does ‘no hay’ mean?", "options": ["there isn’t / there aren’t", "there is definitely one", "you are not allowed to go there", "there won’t be one next year"]}'::jsonb, '{"answer": 0, "explain": "no hay = there isn’t/aren’t, the negative of hay. It does not mean ‘forbidden’ or change the tense."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:c5771e75', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe places and say where they are?", "reading": "<p>Adjectives to describe a place (remember they must agree with the noun):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"grande\">grande</span></td><td>big</td><td><span data-say=\"pequeño\">pequeño / pequeña</span></td><td>small</td></tr>\n              <tr><td><span data-say=\"ruidoso\">ruidoso / ruidosa</span></td><td>noisy</td><td><span data-say=\"tranquilo\">tranquilo / tranquila</span></td><td>quiet</td></tr>\n              <tr><td><span data-say=\"limpio\">limpio / limpia</span></td><td>clean</td><td><span data-say=\"sucio\">sucio / sucia</span></td><td>dirty</td></tr>\n              <tr><td><span data-say=\"animado\">animado / animada</span></td><td>lively</td><td></td><td></td></tr>\n            </table>\n            <p>Use <strong>estar</strong> for location, with prepositions of place:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"al lado de\">al lado de</span></td><td>next to</td><td><span data-say=\"enfrente de\">enfrente de</span></td><td>opposite</td></tr>\n              <tr><td><span data-say=\"entre\">entre</span></td><td>between</td><td><span data-say=\"cerca de\">cerca de</span></td><td>near</td></tr>\n              <tr><td><span data-say=\"lejos de\">lejos de</span></td><td>far from</td><td><span data-say=\"en las afueras\">en las afueras</span></td><td>on the outskirts</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Mi barrio es animado pero un poco ruidoso; el parque está entre la estación y el centro comercial.\">Mi barrio es animado pero un poco ruidoso; el parque está entre la estación y el centro comercial.</span></p>", "question": "In the model sentence, where is ‘el parque’?", "options": ["between the station and the shopping centre", "next to the town hall in the centre", "far from the town centre and the train station", "opposite the sports centre and the shops"]}'::jsonb, '{"answer": 0, "explain": "está entre… y… = it is between… and… — the park is between the station and the shopping centre."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:0ac19564', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "Higher: comparing places and the imperfect tense", "reading": "<p><span class=\"tier-h\">H</span> To compare two places, use <strong>más / menos + adjective + que</strong>:</p>\n            <ul>\n              <li><span data-say=\"Mi pueblo es más tranquilo que la ciudad.\">Mi pueblo es más tranquilo que la ciudad.</span> — My town is quieter than the city.</li>\n              <li><span data-say=\"La ciudad es menos tranquila que mi pueblo.\">La ciudad es menos tranquila que mi pueblo.</span> <span class=\"tier-h\">H</span> — The city is less quiet than my town.</li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> To describe how things used to be, use the <strong>imperfect tense</strong> (vivía, había, era):</p>\n            <ul>\n              <li><span data-say=\"Antes vivía en un piso pequeño en la ciudad.\">Antes vivía en un piso pequeño en la ciudad.</span> — I used to live in a small flat in the city.</li>\n              <li><span data-say=\"De niño, no había centro comercial en mi barrio.\">De niño, no había centro comercial en mi barrio.</span> <span class=\"tier-h\">H</span> — As a child, there wasn’t a shopping centre in my area.</li>\n            </ul>", "question": "What does ‘Antes vivía en un piso pequeño’ mean?", "options": ["I used to live in a small flat", "I live in a small flat right now", "I am going to live in a small flat", "I would like to live in a small flat"]}'::jsonb, '{"answer": 0, "explain": "vivía is the imperfect tense = I used to live. It describes a past habitual state, not the present or future."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:48262144', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "How do I ask for and give directions?", "reading": "<p>Use <span data-say=\"la dirección\">la dirección</span> (address/direction) to ask the way, <span data-say=\"cruzar\">cruzar</span> (to cross) and <span data-say=\"el punto\">el punto</span> (point) to describe a route, and <span data-say=\"fuera\">fuera</span> (outside) to say where something is.</p>\n            <p><span data-say=\"Perdón, ¿me puede dar la dirección al ayuntamiento?\">— Perdón, ¿me puede dar la dirección al ayuntamiento?</span><br>\n            <span data-say=\"Sí, claro. Tiene que cruzar la plaza; el punto de información turística está justo fuera de la estación.\">— Sí, claro. Tiene que cruzar la plaza; el punto de información turística está justo fuera de la estación.</span><br>\n            <span data-say=\"Muchas gracias.\">— Muchas gracias.</span></p>", "question": "According to the dialogue, where exactly is the tourist information point?", "options": ["just outside the station", "inside the town hall, near the plaza entrance", "opposite the train station main entrance", "next to the shopping centre car park entrance"]}'::jsonb, '{"answer": 0, "explain": "‘fuera de la estación’ = outside the station. The other options invent a different building or location that isn’t in the dialogue."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:learn:787e8b97', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe my neighbourhood in more detail?", "reading": "<p>More vocabulary for describing where you live:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el lugar\">el lugar</span></td><td>place</td><td><span data-say=\"el sitio\">el sitio</span></td><td>site / place</td></tr>\n              <tr><td><span data-say=\"la comunidad\">la comunidad</span></td><td>community</td><td><span data-say=\"el vecino\">el vecino / la vecina</span></td><td>neighbour</td></tr>\n              <tr><td><span data-say=\"la entrada\">la entrada</span></td><td>entrance</td><td><span data-say=\"la pared\">la pared</span></td><td>wall</td></tr>\n              <tr><td><span data-say=\"la piedra\">la piedra</span></td><td>stone</td><td><span data-say=\"el metro\">el metro</span></td><td>metre / underground</td></tr>\n            </table>\n            <p>Model paragraph: <span data-say=\"Vivo en un lugar pequeño, casi como una isla tranquila, en un sitio cerca del río. Es una comunidad muy unida donde los vecinos se ayudan. La entrada de mi casa tiene una pared de piedra, y a diez metros hay una plaza de estilo colonial donde se venden productos locales. El espacio físico del pueblo no es grande — su tamaño es pequeño — y ahora mismo hay obras cerca de la iglesia, que lleva el nombre de un santo; por eso, algunas tiendas están abandonadas temporalmente.\">Vivo en un lugar pequeño, casi como una isla tranquila, en un sitio cerca del río. Es una comunidad muy unida donde los vecinos se ayudan. La entrada de mi casa tiene una pared de piedra, y a diez metros hay una plaza de estilo colonial donde se venden productos locales. El espacio físico del pueblo no es grande — su tamaño es pequeño — y ahora mismo hay obras cerca de la iglesia, que lleva el nombre de un santo; por eso, algunas tiendas están abandonadas temporalmente.</span> — <em>I live in a small place, almost like a quiet island, on a site near the river. It''s a very close-knit community where the neighbours help each other. My house''s entrance has a stone wall, and ten metres away there''s a colonial-style square where local products are sold. The physical space of the village isn''t big — its size is small — and right now there are roadworks near the church, which is named after a saint; because of this, some shops are temporarily abandoned.</em></p>", "question": "According to the paragraph, why are some shops temporarily closed?", "options": ["because of roadworks near the church", "because the whole community voted to close them down", "because the village is too small to need any shops", "because the neighbours all abandoned the square together"]}'::jsonb, '{"answer": 0, "explain": "‘hay obras cerca de la iglesia… algunas tiendas están abandonadas temporalmente’ = there are roadworks near the church, so some shops are temporarily closed/abandoned."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:misc:2ce68512', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> El parque es cerca de mi casa.</p><p><strong>✅ The correct idea:</strong> El parque está cerca de mi casa.</p>", "question": "Why is ‘es’ wrong here?", "options": ["location needs ‘estar’, not ‘ser’", "‘cerca’ must come before ‘el parque’", "‘casa’ needs the article ‘un’ instead", "the sentence needs the imperfect tense"]}'::jsonb, '{"answer": 0, "explain": "Location always uses estar: el parque está cerca de mi casa."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:misc:c7795dc3', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Hay piscinas en mi barrio, pero no han restaurantes.</p><p><strong>✅ The correct idea:</strong> Hay piscinas en mi barrio, pero no hay restaurantes.</p>", "question": "What is wrong with ‘no han restaurantes’?", "options": ["‘hay’ never changes form, even for plurals", "‘restaurantes’ should be written in the singular", "‘no’ should come straight after the verb", "‘piscinas’ needs the article ‘las’ in front"]}'::jsonb, '{"answer": 0, "explain": "hay is invariable — it never becomes ‘han’, whether singular or plural."}'::jsonb),
